<template>
  <v-stepper v-model="currentStep">
    <camera-dialog @captureClose="onCaptureClose" @cancelClose="onCancelClose"></camera-dialog>

    <v-stepper-items
      v-touch="{
        left: () => swipe('Left'),
        right: () => swipe('Right'),
      }"
    >
      <v-stepper-content
        v-for="n in steps"
        :key="`${n}-content`"
        :step="n"
      >
        <v-layout align-center row justify-center>
         <v-flex xs6>
            <v-text-field label="Full Name"  v-model="member.fullName" v-if="member" :rules="[rules.required]"></v-text-field>
          </v-flex>
        </v-layout>
        <v-layout row fill-height>
          <v-flex xs12>
              <v-btn :color="idBtnColor" class="headline" @click.native="showDialog(false)">{{ $t(idBtnLabel) }}</v-btn>
          </v-flex>
        </v-layout>  
        <v-layout row fill-height>
          <v-flex xs12>
            <v-container fluid>
              <v-layout row justify-space-between>
                <v-flex xs12>
                  <img :src="member.idImgSrc" class="img-responsive" :width="imgWidth" @click="showDialog(true)" style="cursor: pointer;"/>
                </v-flex>
              </v-layout>
            </v-container>
          </v-flex>
        </v-layout>
<!-- 
        <v-layout row fill-height>
          <v-flex xs12>
            <v-container fluid>
              <v-layout row justify-center>
                <v-flex xs3>
                  <v-text-field label="*Name" required hint="*" v-model="member.firstName" v-if="member" ></v-text-field>
                </v-flex>
              </v-layout>
            </v-container>
          </v-flex>
        </v-layout>
-->      
        <v-layout row fill-height>
          <v-toolbar
            slot="footer"
            class="mt-2"
            color="primary"
            dark
            dense
            flat
          >
          <v-flex xs12>
            <v-spacer></v-spacer>
            <v-btn class="headline" icon @click="prevStep(n)">
              <v-icon x-large>navigate_before</v-icon>
            </v-btn>
            <span class="headline">{{ currentStep }} / {{ steps }}</span>
            <v-btn class="headline" icon @click="nextStep(n)">
              <v-icon x-large>navigate_next</v-icon>
            </v-btn>
          </v-flex>
          </v-toolbar>
        </v-layout> 
        
      </v-stepper-content>
    </v-stepper-items>
  </v-stepper>
</template>

<script>
import MiniCameraDialog from '@/components/MiniCameraDialog.vue'
import { EventBus } from '@/eventBus'
import { Storage } from 'aws-amplify'
import aws_exports from '@/aws-exports'
import { mapState, mapGetters, mapActions } from 'vuex'
import { CallDialog } from '@/utils'
import store from '@/store'

export default {
  name: 'CheckIn',
  data () {
    return {
      rules: {
        required: value => !!value || 'Please set your full name first.',
      },
    }
  },
  created () {
    this.setCurrentStep(1)
  },
  async beforeRouteEnter (to, from, next) {
    const error = await store.dispatch('checkIn/loadMembers').catch(error => {
      return error
    })

    if (error) {
      CallDialog(error)
    } else {
      next()
    }
  },
  async beforeRouteUpdate (to, from, next) {
    const error = await store.dispatch('checkIn/loadMembers').catch(error => {      
      return error
    })

    if (error) {
      CallDialog(error)
    } else {
      next()
    }
  },
  computed: {
    idBtnColor: {
      get() {
        if (this.member.idVerified) {
          return 'success'
        } else {
          if (this.member.idImgName) {
            return 'warning'  
          } else {
            return 'error'
          }
        }
      }
    },
    idBtnLabel: {
      get() {
        if (this.member.idVerified) {
          return 'checkIn.btn_id_verified'
        } else {
          if (this.member.idImgName) {
            return 'checkIn.btn_id_wait'  
          } else {
            return 'checkIn.btn_id_take'
          }
        }
      }
    }, 
    imgWidth: {
      get() {
        if (this.$window.width > this.$window.height) {
          return "60%"
        } else {
          return "100%"
        }
      }
    },
    currentStep: {
      get() {
        return this.$store.state.checkIn.currentStep
      },
      set (val) {
        return this.setCurrentStep(val)
      }
    },
    ...mapState({
      members: state => state.checkIn.members,
      member: state => state.checkIn.currentMember,
    }),
    ...mapGetters('checkIn', {
      steps: 'steps',
    })
  },
  methods: {
    swipe (direction) {
      if (direction === 'Left') {
        this.goNext()
      } else if (direction === 'Right') {
        this.goPrevious()
      }
    },
    prevStep (n) {
      if (n === 1) {
        this.setCurrentStep(this.steps)

      } else {
        this.setCurrentStep(n - 1)
      }
    },
    nextStep (n) {
      if (n === this.steps) {
        this.setCurrentStep(1)
      } else {
        this.setCurrentStep(n + 1)
      }
    },
    goPrevious () {
      this.prevStep(this.currentStep)
    },
    goNext () {
      this.nextStep(this.currentStep)
    },
    showDialog() {
      if (this.member.idVerified) {
        const rtn = window.confirm('ID already verified by the host. Re-taking it will need the host to verify it again. Are you sure?')
        if (!rtn) {
          return
        }
      }

      EventBus.$emit('MiniCameraDialog', { showDialog: true });
    },
    onCancelClose() {
      console.log('on cancel')
    },
    async onCaptureClose(val) {
      if (val.base64Img) {
        await this.putImage({img: val.base64Img, isId: true})       
        
        if (!this.member.fullName) {
          this.member.fullName = null
        }
        
        const error = await this.saveMember(true).catch(e => {
          console.error('saveMember', e)
          return e
        })

        if (error) {
          CallDialog(error)
          return
        } 

        this.goNext()
      }
    },
    ...mapActions({
      setCurrentStep: 'checkIn/setCurrentStep',
      saveMember: 'checkIn/saveMember',
      putImage: 'checkIn/putImage',
      loadMembers: 'checkIn/loadMembers',
    })
  },
  components: {
    cameraDialog: MiniCameraDialog
  }
}
</script>